import type { VariableDef, VariableValues, VisualConcept, VisualSubject } from "./types";

const speed: VariableDef = { key: "speed", label: "Speed", min: 0.2, max: 2.5, step: 0.1, defaultValue: 1 };

function variable(
  key: string,
  label: string,
  min: number,
  max: number,
  step: number,
  defaultValue: number,
  unit?: string
): VariableDef {
  return { key, label, min, max, step, defaultValue, unit };
}

