export const SUBJECT_LABELS: Record<VisualSubject, string> = {
  maths: "Maths",
  physics: "Physics",
  chemistry: "Chemistry",
  nuclear: "Nuclear",
};

export function getDefaultVariables(concept: VisualConcept): VariableValues {
  return Object.fromEntries(concept.variables.map((item) => [item.key, item.defaultValue]));
}

export function getConceptById(id: string) {
  return VISUAL_CONCEPTS.find((concept) => concept.id === id) ?? VISUAL_CONCEPTS[0];
}

export function getConceptsBySubject(subject: VisualSubject) {
  return VISUAL_CONCEPTS.filter((concept) => concept.subject === subject);
}
